#!/usr/bin/env python3
"""Operations daemon — background task scheduler for persistent campaigns."""
import threading, time, json, os, signal, sys, socket

class OperationsDaemon:
    def __init__(self):
        self.tasks = []
        self.running = False
        self._thread = None
        self._lock = threading.Lock()
    def add_task(self, name, func, interval_seconds):
        with self._lock:
            self.tasks.append({'name': name, 'func': func, 'interval': interval_seconds, 'last_run': 0, 'runs': 0, 'errors': 0})
    def start(self):
        self.running = True
        self._thread = threading.Thread(target=self._loop, daemon=True)
        self._thread.start()
    def stop(self):
        self.running = False
        if self._thread:
            self._thread.join(timeout=5)
    def _loop(self):
        while self.running:
            now = time.time()
            for task in self.tasks:
                if now - task['last_run'] >= task['interval']:
                    try:
                        task['func']()
                        task['last_run'] = now
                        task['runs'] += 1
                    except Exception as e:
                        task['errors'] += 1
            time.sleep(1)
    def status(self):
        return {'running': self.running, 'tasks': len(self.tasks),
                'task_details': [{'name': t['name'], 'runs': t['runs'], 'errors': t['errors']} for t in self.tasks]}

if __name__ == '__main__':
    daemon = OperationsDaemon()
    daemon.add_task('heartbeat', lambda: print(f'[*] Alive: {time.strftime("%H:%M:%S")}'), 10)
    daemon.start()
    print('[*] Daemon started. Ctrl+C to stop.')
    try:
        while True:
            time.sleep(1)
    except KeyboardInterrupt:
        daemon.stop()

