SUBNET = '192.168.87.0/24'
GATEWAY = '192.168.87.1'

def arp_scan(subnet):
    hosts = []
    try:
        result = subprocess.run(
            ['nmap', '-sn', '-PR', subnet],
            capture_output=True, text=True, timeout=30,
        )
        for line in result.stdout.splitlines():
            if 'Nmap scan report for' in line:
                ip = line.split()[-1].strip('()')
                hosts.append(ip)
    except Exception:
        # Fallback: ping sweep
        import ipaddress
        for host in ipaddress.ip_network(subnet, strict=False).hosts():
            ip = str(host)
            try:
                subprocess.run(
                    ['ping', '-c', '1', '-W', '1', ip],
                    capture_output=True, timeout=2,
                )
                s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
                s.settimeout(0.5)
                if s.connect_ex((ip, 80)) == 0 or s.connect_ex((ip, 22)) == 0:
                    hosts.append(ip)
                s.close()
            except:
                pass
    return hosts

def port_scan(ip, ports=None):
    if ports is None:
        ports = [21, 22, 23, 25, 53, 80, 110, 139, 143, 443, 445, 993, 995,
                 3306, 3389, 5432, 5900, 8080, 8443]
    open_ports = []
    for port in ports:
        try:
            s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
            s.settimeout(0.5)
            if s.connect_ex((ip, port)) == 0:
                open_ports.append(port)
            s.close()
        except:
            pass
    return open_ports

def discover():
    hosts = arp_scan(SUBNET)
    results = []
    for ip in hosts:
        ports = port_scan(ip)
        results.append({'ip': ip, 'ports': ports})
    return results

if __name__ == '__main__':
    print(json.dumps(discover(), indent=2))

