#!/usr/bin/env python3
"""Operations TUI — 5-panel curses dashboard for campaign management."""
import curses, time, threading, json

class Panel:
    MAX_LINES = 500
    def __init__(self, name, win, title, color_pair):
        self.name, self.win, self.title, self.color_pair = name, win, title, color_pair
        self.lines, self.scroll_offset = [], 0
    def add_line(self, text, color=0):
        self.lines.append((text, color))
        if len(self.lines) > self.MAX_LINES:
            self.lines = self.lines[-self.MAX_LINES:]
    def clear_lines(self):
        self.lines, self.scroll_offset = [], 0
    def scroll_down(self, n=1):
        h, _ = self.win.getmaxyx()
        self.scroll_offset = min(max(0, len(self.lines) - (h - 2)), self.scroll_offset + n)
    def scroll_up(self, n=1):
        self.scroll_offset = max(0, self.scroll_offset - n)
    def render(self):
        try:
            self.win.erase(); self.win.box()
            h, w = self.win.getmaxyx()
            self.win.addstr(0, 2, f' {self.title} ', curses.color_pair(self.color_pair) | curses.A_BOLD)
            for i, (text, color) in enumerate(self.lines[self.scroll_offset:self.scroll_offset+h-2]):
                try: self.win.addstr(i+1, 1, text[:w-2], curses.color_pair(color))
                except curses.error: pass
            self.win.noutrefresh()
        except curses.error: pass

def main(stdscr):
    curses.curs_set(0); curses.start_color(); curses.use_default_colors()
    for i, (fg, bg) in enumerate([(curses.COLOR_GREEN,-1),(curses.COLOR_YELLOW,-1),
        (curses.COLOR_RED,-1),(curses.COLOR_CYAN,-1),(curses.COLOR_MAGENTA,-1),(curses.COLOR_WHITE,-1)],1):
        curses.init_pair(i, fg, bg)
    stdscr.timeout(100)
    h, w = stdscr.getmaxyx()
    panels = {
        'network': Panel('net', curses.newwin(h//2,w//2,0,0), 'NETWORK', 1),
        'creds': Panel('cred', curses.newwin(h//2,w//2,0,w//2), 'CREDENTIALS', 2),
        'alerts': Panel('alert', curses.newwin(h//4,w//2,h//2,0), 'ALERTS', 3),
        'actions': Panel('act', curses.newwin(h//4,w//2,h//2,w//2), 'ACTIONS', 4),
        'cmd': Panel('cmd', curses.newwin(h//4,w,3*h//4,0), 'COMMAND', 5),
    }
    panels['network'].add_line('[*] 10.0.0.1 dc01 Win2019 x64 [COMPROMISED]', 1)
    panels['creds'].add_line('[NTLM] CORP\\admin aad3b435... (dc01)', 2)
    panels['alerts'].add_line('[CRITICAL] EDR detected on dc01', 3)
    panels['actions'].add_line('[RECON] 10.0.0.0/24 -> 5 hosts', 1)
    panels['cmd'].add_line('Press q to quit, :cmd for command mode', 5)
    while True:
        for p in panels.values(): p.render()
        curses.doupdate()
        if stdscr.getch() == ord('q'): break

if __name__ == '__main__':
    curses.wrapper(main)

